986	\begin{theorem}[Čech acyclicity for the structure sheaf]
987	  \label{thm:basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
988	  \lean{AlgebraicGeometry.Scheme.basicOpenCover_isCechAcyclicCover_toModuleKSheaf}
989	  \uses{def:Scheme_basicOpenCover, def:Scheme_IsCechAcyclicCover, thm:Scheme_basicOpenCover_finset_inf_eq_basicOpen_prod, thm:Scheme_basicOpenCover_finset_inf_le, thm:Scheme_basicOpenCover_finset_inf_isLocalization, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
990	  The Čech cohomology $\check H^n(\mathfrak U, \mathcal O_X)$ vanishes for every $n \ge 1$.
991	\end{theorem}
992	
993	\begin{proof}
994	  \uses{thm:Scheme_basicOpenCover_finset_inf_isLocalization, def:Scheme_IsCechAcyclicCover, thm:Scheme_cechCohomology_subsingleton_of_cechCochain_exactAt, def:Scheme_splitEpi_pi_lift_of_injective}
995	  The classical proof proceeds in four steps.
996	
997	  \textbf{Step~1: Reduction to per-generator local exactness.} Since $s$ generates the unit ideal, exactness of a map of $\mathcal O_X(U)$-modules is a local property at the cover $\{D(f)\}_{f \in s}$. It suffices to prove exactness after localizing at each generator $f \in s$.
998	
999	  \textbf{Step~2: Identification of the localized complex.} Localizing at $f$ identifies the factor at $(f_0,\dots,f_n)$ with $\mathcal O_X(U)[1/(f f_0 \cdots f_n)]$. Reassembling, the localized Čech complex is naturally isomorphic to the Čech complex of $D(f)$ with respect to the restricted cover $\{D(f) \cap D(f')\}_{f' \in s}$.
1000	
1001	  \textbf{Step~3: Contraction by extra degeneracy.} In the cover of $D(f)$, the member indexed by $f' = f$ is $D(f)$ itself. The augmented Čech complex therefore admits a section: map a family to its component at $f$. This section extends to an extra degeneracy on the augmented simplicial object, exhibiting the augmented Čech complex as contractible. Consequently the complex is exact in all positive degrees.
1002	
1003	  \textbf{Step~4: Globalization.} Each localized differential is exact, so the unlocalized differential is exact by the local-to-global principle for spanning sets. Hence $\check H^n(\mathfrak U, \mathcal O_X) = 0$ for $n \ge 1$.
1004	\end{proof}
